// Event types
type AccountEvent = 
  | { type: 'Deposited'; amount: number; timestamp: number }
  | { type: 'Withdrawn'; amount: number; timestamp: number }
  | { type: 'Transferred'; amount: number; to: string; timestamp: number };

// Account aggregate
class Account {
  private balance: number = 0;
  private events: AccountEvent[] = [];
  private accountId: string;

  constructor(accountId: string) {
    this.accountId = accountId;
  }

  deposit(amount: number): void {
    if (amount <= 0) throw new Error('Deposit amount must be positive');

    const event: AccountEvent = {
      type: 'Deposited',
      amount,
      timestamp: Date.now()
    };

    this.applyEvent(event);
    this.events.push(event);
  }

  withdraw(amount: number): void {
    if (amount <= 0) throw new Error('Withdrawal amount must be positive');
    if (this.balance < amount) throw new Error('Insufficient funds');

    const event: AccountEvent = {
      type: 'Withdrawn',
      amount,
      timestamp: Date.now()
    };

    this.applyEvent(event);
    this.events.push(event);
  }

  transfer(amount: number, toAccountId: string): void {
    if (amount <= 0) throw new Error('Transfer amount must be positive');
    if (this.balance < amount) throw new Error('Insufficient funds');
    if (!toAccountId) throw new Error('Recipient account must be specified');

    const event: AccountEvent = {
      type: 'Transferred',
      amount,
      to: toAccountId,
      timestamp: Date.now()
    };

    this.applyEvent(event);
    this.events.push(event);
  }

  private applyEvent(event: AccountEvent): void {
    switch (event.type) {
      case 'Deposited':
        this.balance += event.amount;
        break;
      case 'Withdrawn':
        this.balance -= event.amount;
        break;
      case 'Transferred':
        this.balance -= event.amount;
        break;
    }
  }

  getBalance(): number {
    return this.balance;
  }

  getEvents(): AccountEvent[] {
    return [...this.events];
  }

  static fromEvents(accountId: string, events: AccountEvent[]): Account {
    const account = new Account(accountId);
    events.forEach(event => account.applyEvent(event));
    account.events = [...events];
    return account;
  }
}
